import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Login from './pages/Login';
import Register from './pages/Register';
import InterviewerAvailability from './pages/interviewer/InterviewerAvailability';

function App() {
  return (
    <Router>
      <Routes>
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />
        <Route path="/interviewer/availability" element={<InterviewerAvailability />} />
        <Route path="/" element={<h1 className="text-center mt-10">Welcome to Mock Interview Platform</h1>} />
      </Routes>
    </Router>
  );
}

export default App;
